def admet_filter(compounds):
    """
    Filter compounds based on ADMET properties.
    """
    results = {'passed': [], 'failed': [], 'warnings': []}

    for comp in compounds:
        violations = []
        warnings_list = []

        # Lipinski violations
        if comp['mw'] > 500:
            violations.append('MW > 500')
        if comp['logp'] > 5:
            violations.append('LogP > 5')
        if comp['hbd'] > 5:
            violations.append('HBD > 5')
        if comp['hba'] > 10:
            violations.append('HBA > 10')

        # Veber violations
        if comp['psa'] > 140:
            violations.append('PSA > 140')
        if comp['rotbonds'] > 10:
            violations.append('RotBonds > 10')

        # Solubility
        if comp['solubility'] < 1:
            violations.append('Low solubility')

        # hERG
        if comp['herg_ic50'] < 1:
            violations.append('hERG IC50 < 1 μM (high risk)')
        elif comp['herg_ic50'] < 10:
            warnings_list.append('hERG IC50 1-10 μM (caution)')

        # Categorize
        compound_result = {
            'name': comp['name'],
            'violations': violations,
            'warnings': warnings_list,
            'n_violations': len(violations)
        }

        if len(violations) == 0:
            if warnings_list:
                results['warnings'].append(compound_result)
            else:
                results['passed'].append(compound_result)
        elif len(violations) == 1 and 'hERG' not in violations[0]:
            results['warnings'].append(compound_result)
        else:
            results['failed'].append(compound_result)

    return results

def identify_soft_spots(smiles_patterns):
    """
    Identify metabolic soft spots from structural features.
    """
    soft_spots = []
    recommendations = []

    metabolism_risks = {
        'benzylic_CH': {
            'risk': 'Benzylic hydroxylation (CYP oxidation)',
            'severity': 'High',
            'fix': 'Replace with F or CF3'
        },
        'N_methyl': {
            'risk': 'N-demethylation',
            'severity': 'Medium',
            'fix': 'Use cyclopropyl or isopropyl instead'
        },
        'thioether': {
            'risk': 'S-oxidation to sulfoxide/sulfone',
            'severity': 'High',
            'fix': 'Replace S with O or CH2'
        },
        'terminal_alkyl': {
            'risk': 'ω and ω-1 hydroxylation',
            'severity': 'Medium',
            'fix': 'Add branching or fluorine'
        },
        'aromatic_para': {
            'risk': 'Para-hydroxylation',
            'severity': 'Medium',
            'fix': 'Block with F or Cl'
        },
        'ester': {
            'risk': 'Esterase hydrolysis',
            'severity': 'High',
            'fix': 'Replace with amide'
        }
    }

    for feature, count in smiles_patterns.items():
        if count > 0 and feature in metabolism_risks:
            risk_info = metabolism_risks[feature]
            soft_spots.append({
                'feature': feature,
                'count': count,
                'risk': risk_info['risk'],
                'severity': risk_info['severity'],
                'recommendation': risk_info['fix']
            })

    return soft_spots
